const path = require('path');
const fs = require('fs');

const problemsPath = path.resolve(__dirname, '../../data/problems.json');

function loadProblems() {
	const data = fs.readFileSync(problemsPath, 'utf8');
	return JSON.parse(data);
}

/**
 * Get detailed problem info by problemId including aggregated component statistics.
 * @param {string} problemId
 * @returns {object} problem detail with component stats or null if not found
 */
function getProblemDetail(problemId) {
	const problems = loadProblems();
	const problem = problems.find(p => p.id === problemId);
	if (!problem) return null;

	// Aggregate component statistics
	const languageCounts = {};
	const statusCounts = {};
	let maxPoints = 0;

	if (problem.components && Array.isArray(problem.components)) {
		for (const comp of problem.components) {
			if (comp.language) {
				languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
			}
			if (comp.status) {
				statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
			}
			if (typeof comp.points === 'number' && comp.points > maxPoints) {
				maxPoints = comp.points;
			}
		}
	}

	return {
		...problem,
		componentStats: {
			languageCounts,
			statusCounts,
			maxPoints,
		},
	};
}

module.exports = {
	getProblemDetail,
};
